struct Promo {
    let code: String
    let discountPercentage: Int
    let sourceURL: URL
}

final class PromoLinkParser {
    static func parse(url: URL) -> Promo? {
        guard url.scheme?.lowercased() == "https",
              url.host?.lowercased() == "myapp.com",
              url.path.lowercased() == "/promo" else { return nil }

        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let items = components.queryItems else { return nil }

        let code = items.first(where: { $0.name == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountString = items.first(where: { $0.name == "discount" })?.value

        guard let code, !code.isEmpty,
              let discountString,
              let discount = Int(discountString),
              (0...100).contains(discount) else { return nil }

        return Promo(code: code, discountPercentage: discount, sourceURL: url)
    }
}

final class PromoManager {
    static let shared = PromoManager()

    private(set) var currentPromo: Promo?

    private init() {}

    func apply(promo: Promo) {
        currentPromo = promo
        applyDiscountToUserAccount(code: promo.code, discountPercentage: promo.discountPercentage)
    }

    private func applyDiscountToUserAccount(code: String, discountPercentage: Int) {
        let defaults = UserDefaults.standard
        defaults.set(code, forKey: "promo_code")
        defaults.set(discountPercentage, forKey: "promo_discount")
        defaults.set(Date(), forKey: "promo_applied_at")

        if let userID = defaults.string(forKey: "current_user_id") {
            updateBackendAccount(userID: userID, promoCode: code, discountPercentage: discountPercentage)
        }
    }

    private func updateBackendAccount(userID: String, promoCode: String, discountPercentage: Int) {
        guard let url = URL(string: "https://api.myapp.com/users/\(userID)/promo") else { return }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = [
            "promoCode": promoCode,
            "discountPercentage": discountPercentage
        ]

        request.httpBody = try? JSONSerialization.data(withJSONObject: body, options: [])

        URLSession.shared.dataTask(with: request).resume()
    }
}

